// JSI HostObject (C++ side — simplified):
class NativeStorageHostObject : public jsi::HostObject {
  jsi::Value get(jsi::Runtime& rt, const jsi::PropNameID& name) override {
    auto nameStr = name.utf8(rt);
    if (nameStr == "getString") {
      return jsi::Function::createFromHostFunction(rt, name, 1,
        [this](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t) {
          auto key = args[0].asString(rt).utf8(rt);
          return jsi::String::createFromUtf8(rt, mmkvStorage.getString(key));
          // SYNCHRONOUS return — no callback needed!
        });
    }
    return jsi::Value::undefined();
  }
};

// Install JSI module (called from React Native's setupJsi):
void install(jsi::Runtime& rt) {
  auto storage = std::make_shared<NativeStorageHostObject>();
  rt.global().setProperty(rt, "__NativeStorage",
    jsi::Object::createFromHostObject(rt, storage));
}

