import JailMonkey from 'react-native-jailmonkey';

// Check device security on app launch:
async function checkDeviceSecurity() {
  const isJailbroken = JailMonkey.isJailBroken();
  const isDebugged = JailMonkey.hookDetected();
  const isOnExternalStorage = JailMonkey.isOnExternalStorage();
  const hasAdbEnabled = JailMonkey.AdbEnabled(); // Android only

  if (isJailbroken) {
    Alert.alert(
      'Security Warning',
      'This device is jailbroken/rooted. App cannot run securely.',
      [{ text: 'Exit', onPress: () => RNExitApp.exitApp() }]
    );
    return false;
  }
  return true;
}

